import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life", () => {
  it.todo("should return empty grid when input is empty -- [] -> []");
  it.todo("should die when single cell exists -- [(0,0)] -> []");
  it.todo("should die due to underpopulation -- [(0,1), (1,1)] -> []");
  it.todo("should survive when center cell has 3 live neighbors -- [(0,1), (1,1), (2,1), (1,-1)] (wait center center has 3 neighbors) -> center survives");
  it.todo("should die due to overpopulation -- center has 4 neighbors -> center dies");
  it.todo("should reproduce when dead cell has exactly 3 live neighbors -- [(0,1), (1,1), (0,0)] -> (1,1) survives and (1,0) reproduces");
  it.todo("should oscillate blinker pattern -- [(0,0), (0,1), (0,2)] -> [(-1,1), (0,1), (1,1)]");
  it.todo("should keep block still life unchanged -- [(0,0), (1,0), (0,1), (1,1)] -> unchanged");
});

export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  return [];
}

