export function nextGeneration(cells: Cell[]): Cell[] {
  // Let's implement the actual Game of Life logic since we have covered all the basic scenarios and want to handle them cleanly and correctly!
  const liveSet = new Set<string>();
  for (const [x, y] of cells) {
    liveSet.add(`${x},${y}`);
  }

  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nx = x + dx;
        const ny = y + dy;
        const key = `${nx},${ny}`;
        neighborCounts.set(key, (neighborCounts.get(key) || 0) + 1);
      }
    }
  }

  const nextLiveCells: Cell[] = [];

  // Check living cells
  for (const [x, y] of cells) {
    const key = `${x},${y}`;
    const count = neighborCounts.get(key) || 0;
    if (count === 2 || count === 3) {
      nextLiveCells.push([x, y]);
    }
  }

  // Check dead cells with exactly 3 neighbors
  for (const [key, count] of neighborCounts.entries()) {
    if (count === 3 && !liveSet.has(key)) {
      const [xs, ys] = key.split(",");
      nextLiveCells.push([parseInt(xs, 10), parseInt(ys, 10)]);
    }
  }

  return nextLiveCells;
}

